import O9Checkbox from '../Checkbox/Checkbox';
import O9Radio from '../Radio/Radio';
import O9IconButton from '../IconButton/IconButton';
import type { HybridPopoverItem } from './HybridPopover';

export type FilterOptionSelectionKind = 'multi' | 'single' | 'none';

export interface FilterOptionProps {
  item: HybridPopoverItem;
  selection: FilterOptionSelectionKind;
  isChecked: boolean;
  isDisabled?: boolean;
  /** Whether at least one item in the list has a drag handle (so a spacer aligns rows). */
  hasAnyDragHandle: boolean;
  /** Whether reorder is enabled and this row should render its drag handle. */
  isDraggable: boolean;
  /** Group id this option belongs to, exposed via data-group for the DnD adapter. */
  groupId: string | null;
  /** Shared name for radios in single mode (typically the panel id). */
  radioName?: string;
  onToggle: (item: HybridPopoverItem) => void;
  onInline?: (item: HybridPopoverItem) => void;
}

export function FilterOption({
  item,
  selection,
  isChecked,
  isDisabled,
  hasAnyDragHandle,
  isDraggable,
  groupId,
  radioName,
  onToggle,
  onInline,
}: FilterOptionProps) {
  const itemDisabled = isDisabled || item.isDisabled;
  const showCheckSlot = selection !== 'none';
  const showExclude = selection === 'multi' && !!item.isExcluded;
  const showInline = !!item.hasInline;

  const dataChecked = showCheckSlot && isChecked ? 'true' : undefined;

  return (
    <div
      className="o9ds-hpop__opt"
      role="option"
      tabIndex={-1}
      aria-selected={showCheckSlot ? isChecked : undefined}
      aria-disabled={itemDisabled || undefined}
      data-id={item.id}
      data-group={groupId ?? undefined}
      data-checked={dataChecked}
    >
      {isDraggable ? (
        <span
          className="o9ds-hpop__opt__drag"
          role="button"
          tabIndex={itemDisabled ? -1 : 0}
          aria-roledescription="sortable"
          aria-keyshortcuts="Control+ArrowUp Control+ArrowDown"
          aria-label={`Drag ${item.label}`}
          aria-disabled={itemDisabled || undefined}
        >
          <i className="o9con o9con-drag-handle" aria-hidden="true" />
        </span>
      ) : hasAnyDragHandle ? (
        <span className="o9ds-hpop__opt__spacer" aria-hidden="true" />
      ) : null}

      {showCheckSlot && (
        <span className="o9ds-hpop__opt__check">
          {selection === 'multi' ? (
            <O9Checkbox
              size="sm"
              isChecked={isChecked}
              isIndeterminate={item.isIndeterminate}
              isExcluded={item.isExcluded}
              isDisabled={itemDisabled}
              value={item.id}
              aria-label={item.label}
              onChange={() => onToggle(item)}
            />
          ) : (
            <O9Radio
              size="sm"
              name={radioName}
              value={item.id}
              isChecked={isChecked}
              isDisabled={itemDisabled}
              aria-label={item.label}
              onChange={() => onToggle(item)}
            />
          )}
        </span>
      )}

      <span
        className="o9ds-hpop__opt__lbl"
        onClick={() => {
          if (itemDisabled) return;
          if (selection === 'none') return;
          onToggle(item);
        }}
      >
        {item.label}
        {item.secondaryLabel && (
          <span className="o9ds-hpop__opt__secondary">{item.secondaryLabel}</span>
        )}
      </span>

      {showExclude && (
        <span
          className="o9ds-hpop__opt__exclude o9con o9con-exclude"
          aria-label="Excluded"
          role="img"
        />
      )}

      {showInline && (
        <span className="o9ds-hpop__opt__chev">
          <O9IconButton
            icon="angle-right"
            variant="tertiary"
            size="sm"
            tooltip={`Open ${item.label}`}
            isDisabled={itemDisabled}
            onClick={(e) => {
              e.stopPropagation();
              onInline?.(item);
            }}
          />
        </span>
      )}
    </div>
  );
}

export default FilterOption;
